#include <bits/stdc++.h>
using namespace std;
const int MAXN = 1000010;
struct P {
	int a, b;
} p[MAXN];
int k, n, tot, cnt, x1, x2, pl[MAXN];
long long ans, haf[2][MAXN], s1, s2;
char c1, c2;
priority_queue <int, vector<int>, less<int> > q1;
priority_queue <int, vector<int>, greater<int> > q2;
bool cmp (P a, P b) {
	return a.a + a.b < b.a + b.b;
}
int main () {
	cin >> k >> n;
	for (int i = 1; i <= n; i++) {
		cin >> c1 >> x1 >> c2 >> x2;
		if (c1 == c2) {
			ans += abs(x2 - x1);
		} else {
			ans++, p[++tot].a = x1;
			p[tot].b = x2, pl[++cnt] = x1;
			pl[++cnt] = x2;
		}
	}
	if (k == 1) {
		sort(pl + 1, pl + cnt + 1);
		int pos = pl[cnt / 2];
		for (int i = 1; i <= cnt; i++) {
			ans += abs(pl[i] - pos);
		}
		cout << ans << endl;
	} else {
		sort(p + 1, p + tot + 1, cmp);
		for (int i = 1; i <= tot; i++) {
			q1.push(p[i].a), q1.push(p[i].b);
			s1 += p[i].a + p[i].b;
			s2 += q1.top(), s1 -= q1.top(), q2.push(q1.top());
			q1.pop();
			if (q1.top() > q2.top()) {
				int t = q2.top(), l = q1.top();
				q2.pop(), q1.pop();
				q2.push(l), q1.push(t);
				s1 += t - l, s2 -= t - l;
			}
			haf[0][i] = s2 - s1;
		}
		while (!q1.empty()) {
			q1.pop();
		}
		while (!q2.empty()) {
			q2.pop();
		}
		s1 = s2 = 0;
		for (int i = tot; i >= 1; i--) {
			q1.push(p[i].a), q1.push(p[i].b);
			s1 += p[i].a + p[i].b;
			s2 += q1.top(), s1 -= q1.top(), q2.push(q1.top());
			q1.pop();
			if (q1.top() > q2.top()) {
				int t = q2.top(), l = q1.top();
				q2.pop(), q1.pop();
				q2.push(l), q1.push(t);
				s1 += t - l, s2 -= t - l;
			}
			haf[1][i] = s2 - s1;
		}
		long long mn = 1e18;
		for (int i = 1; i <= tot + 1; i++) {
			mn = min(mn, haf[0][i - 1] + haf[1][i]);
		}
		cout << mn + ans;
	}
	return 0;
}
